import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  // Validation state
  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  // Validation helpers
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!isValidEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const isStep1Valid = (): boolean => {
    return formData.name.trim() !== '' && isValidEmail(formData.email);
  };

  // Handlers
  const handleNameChange = (value: string) => {
    setFormData((prev) => ({ ...prev, name: value }));
    if (errors.name) setErrors((prev) => ({ ...prev, name: '' }));
  };

  const handleEmailChange = (value: string) => {
    setFormData((prev) => ({ ...prev, email: value }));
    if (errors.email) setErrors((prev) => ({ ...prev, email: '' }));
  };

  const handleSatisfactionChange = (value: string) => {
    setFormData((prev) => ({ ...prev, satisfaction: parseInt(value, 10) }));
  };

  const handleFeatureToggle = (feature: string) => {
    setFormData((prev) => {
      const isSelected = prev.features.includes(feature);
      return {
        ...prev,
        features: isSelected
          ? prev.features.filter((f) => f !== feature)
          : [...prev.features, feature],
      };
    });
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setFormData((prev) => ({ ...prev, comments: value }));
    }
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (!validateStep1()) {
        return;
      }
    }
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Bar */}
        <Box aria-label="Progress section">
          <Stack gap="var(--ggui-spacing-3)" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 4
            </Text>
            <Progress
              value={currentStep}
              max={4}
              variant="default"
              size="md"
            />
          </Stack>
        </Box>

        {/* Step 1: Personal Information */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Your Information</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please provide your name and email address
              </Text>

              <Stack gap="var(--ggui-spacing-3)">
                <Input
                  label="Full Name"
                  placeholder="John Doe"
                  value={formData.name}
                  onChange={handleNameChange}
                  error={errors.name}
                  required
                />

                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={handleEmailChange}
                  error={errors.email}
                  required
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>How satisfied are you?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please rate your overall satisfaction
              </Text>

              <RadioGroup
                label="Satisfaction Rating"
                value={formData.satisfaction.toString()}
                onChange={handleSatisfactionChange}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: (index + 1).toString(),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Which features interest you?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select all that apply
              </Text>

              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Any additional comments?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Share your thoughts (optional)
              </Text>

              <TextArea
                label="Comments"
                placeholder="Tell us what you think..."
                value={formData.comments}
                onChange={handleCommentsChange}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Summary Step */}
        {currentStep === 5 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Answers</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please review the information below before submitting
              </Text>

              <Stack gap="var(--ggui-spacing-4)" align="stretch">
                {/* Name */}
                <Box
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Name
                    </Text>
                    <Text variant="body">{formData.name}</Text>
                  </Stack>
                </Box>

                {/* Email */}
                <Box
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Email
                    </Text>
                    <Text variant="body">{formData.email}</Text>
                  </Stack>
                </Box>

                {/* Satisfaction */}
                <Box
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body">
                       {formData.satisfaction > 0 ? props.satisfactionLabels[formData.satisfaction - 1] : 'Not selected'}
                    </Text>
                  </Stack>
                </Box>

                {/* Features */}
                <Box
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Features of Interest
                    </Text>
                    {formData.features.length > 0 ? (
                      <Stack gap="var(--ggui-spacing-1)" direction="horizontal" wrap>
                        {formData.features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))}
                      </Stack>
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No features selected
                      </Text>
                    )}
                  </Stack>
                </Box>

                {/* Comments */}
                <Box
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Comments
                    </Text>
                    <Text variant="body">
                      {formData.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row
          gap="var(--ggui-spacing-3)"
          justify="between"
          align="center"
        >
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            {currentStep < 4 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={currentStep === 1 && !isStep1Valid()}
              >
                Next
              </Button>
            )}
            {currentStep === 4 && (
              <Button
                variant="primary"
                onClick={() => setCurrentStep(5)}
              >
                Review
              </Button>
            )}
            {currentStep === 5 && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

