        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns?.map(column => {
            const columnId = column.id || '';
            const tasks = tasksByColumn[columnId] || [];
            const isAdding = addingColumnId === columnId;

            return (
              <Box key={columnId} style={{ flex: '1 1 300px', minWidth: '300px' }}>
                <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
                  <Stack gap="var(--ggui-spacing-3)" direction="vertical">
