                                />
                                <Button size="sm" variant="primary" onClick={() => handleSaveEdit(task.id || '')}>
                                  Save
                                </Button>
                                <Button size="sm" variant="ghost" onClick={() => setEditingTaskId(null)}>
                                  Cancel
                                </Button>
                              </Row>
                            ) : (
                              <Text
                                variant="label"
                                as={Clickable}
                                onClick={() => handleStartEdit(task)}
                                style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-1)' }}
                              >
                                {task.title}
                              </Text>
                            )}

                            {/* Priority badge */}
                            {task.priority && (
                              <Badge variant={getPriorityVariant(task.priority)} size="sm" pill>
                                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                              </Badge>
                            )}

                            {/* Assignee avatar and due date */}
                            <Row gap="var(--ggui-spacing-2)" align="center">
                              {task.assignee && (
                                <Avatar name={task.assignee} size="sm" />
                              )}
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  Due: {new Date(task.dueDate).toLocaleDateString()}
                                </Text>
                              )}
                            </Row>

                            {/* Move button dropdown */}
                            <Dropdown
                              trigger={<Button size="sm" variant="ghost">Move</Button>}
                              options={props.columns?.filter(c => c.id !== columnId).map(c => ({
                                value: c.id || '',
                                label: `Move to ${c.name}`,
                              })) || []}
                              value=""
                              onChange={(targetCol) => handleMoveTask(task.id || '', targetCol)}
                              placement="bottom-start"
                            />
                          </Stack>
                        </Card>
                      ))}
                    </Stack>

                    {/* Add task form */}
                    {isAdding ? (
                      <Card padding="var(--ggui-spacing-3)" shadow="sm" border background="var(--ggui-color-primary-50)">
