                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button
                        size="sm"
                        variant="outline"
                        fullWidth
                        onClick={() => setAddingColumnId(columnId)}
                      >
                        + Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

