  const [activeTab, setActiveTab] = useState('description');

  // Handlers
  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity((prev) => {
      const newQty = Math.max(1, Math.min(props.product.stock || 1, prev + delta));
      return newQty;
    });
  }, [props.product.stock]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
