  // Computed values
  const stockStatus = useMemo(() => {
    const stock = props.product.stock || 0;
    if (stock === 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (stock <= 5) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  }, [props.product.stock]);

  const isOutOfStock = (props.product.stock || 0) === 0;

  // Render rating stars (filled/empty with partial star support)
  const renderStars = () => {
    const rating = props.product.rating || 0;
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      const isFilled = i <= Math.floor(rating);
      const isPartial = !isFilled && i === Math.ceil(rating);
      const partialFill = isPartial ? ((rating % 1) * 100) : 0;
      stars.push(
        <Box key={i} style={{ position: 'relative', display: 'inline-flex' }}>
          <Icon
            name="star"
            size={16}
            color="var(--ggui-color-outlineVariant)"
          />
          {(isFilled || isPartial) && (
            <Box
              style={{
                position: 'absolute',
                top: 0,
                left: 0,
                overflow: 'hidden',
                width: `${isFilled ? 100 : partialFill}%`,
              }}
            >
              <Icon
                name="star"
                size={16}
                color="var(--ggui-color-warning-500)"
              />
            </Box>
          )}
        </Box>
      );
    }
    return stars;
  };

