  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [messages, setMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Append new message from stream
  useEffect(() => {
    if (message.latest) {
      setMessages(prev => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers(prev => ({
        ...prev,
        [typing.latest!.sender || 'unknown']: typing.latest!.active || false
      }));
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const payload: ActionSendMessagePayload = {
        text: inputValue,
        timestamp: new Date().toISOString()
      };
      sendMessage(payload);
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Format timestamp
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages by sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    messages.forEach(msg => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({
          sender: msg.sender,
          messages: [msg]
        });
      }
    });

    return groups;
  }, [messages]);

  // Get active typing users
  const activeTypingUsers = useMemo(() => {
    return Object.entries(typingUsers)
      .filter(([_, isTyping]) => isTyping)
      .map(([sender, _]) => sender)
      .filter(sender => sender !== props.currentUser);
  }, [typingUsers, props.currentUser]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg" border>
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          {/* Header */}
          <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)" direction="vertical">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Message List */}
          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
            role="region"
            aria-label="Chat messages"
            style={{
              overflowY: 'auto',
              maxHeight: '400px',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-3)',
            }}
            {groupedMessages.length === 0 ? (
              <Text color="var(--ggui-color-onSurfaceVariant)" align="center">No messages yet</Text>
            ) : (
              <>
                {groupedMessages.map((group, groupIdx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  return (
                    <Stack
                      key={groupIdx}
                      gap="var(--ggui-spacing-2)"
                      align={isCurrentUser ? 'end' : 'start'}
                      direction="vertical"
                    >
                      {group.messages.map((msg, msgIdx) => (
                        <Card
                          key={msgIdx}
                          padding="var(--ggui-spacing-3)"
                          shadow="sm"
                          radius="md"
                          background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                          style={{ maxWidth: '60%' }}
                          aria-label={`Message from ${group.sender || 'unknown'}: ${msg.text}`}
                          <Stack gap="var(--ggui-spacing-2)" direction="vertical" align="stretch">
                            <Text
                              color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                              variant="body"
                            >
                              {msg.text}
                            </Text>
                            <Text
                              color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                              variant="caption"
                              align="right"
                            >
                              {formatTime(msg.timestamp)}
                            </Text>
                          </Stack>
                        </Card>
                      ))}
                      {!isCurrentUser && group.sender && (
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                          {group.sender}
                        </Text>
                      )}
                    </Stack>
                  );
                })}
                {/* Typing indicator */}
                {activeTypingUsers.length > 0 && (
                  <Stack gap="var(--ggui-spacing-2)" align="start" direction="vertical">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ fontStyle: 'italic' }}>
                      {activeTypingUsers.join(', ')} {activeTypingUsers.length === 1 ? 'is' : 'are'} typing
                    </Text>
                  </Stack>
                )}
                <div ref={messagesEndRef} />
              </>
            )}
          </Box>

          {/* Input Area */}
          <Stack gap="var(--ggui-spacing-2)" align="end" direction="horizontal">
            <TextArea
              label="Message"
              value={inputValue}
              onChange={setInputValue}
              placeholder="Type your message here..."
              rows={3}
              onKeyDown={handleKeyDown}
            />
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!inputValue.trim()}
            >
              Send
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

