  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for managing stocks with live updates
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [updatedSymbols, setUpdatedSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout>();

  // Update stocks from initial props
  useEffect(() => {
    setStocks(props.stocks);
  }, [props.stocks]);

  // Handle real-time price updates from stream
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) =>
        prevStocks.map((stock) =>
          stock.symbol === update.symbol
            ? {
                ...stock,
                price: update.price ?? stock.price,
                change: update.change ?? stock.change,
                changePercent: update.changePercent ?? stock.changePercent,
              }
            : stock
        )
      );
      setLastUpdated(new Date());
      setUpdatedSymbols((prev) => new Set([...(update.symbol ? [update.symbol] : []), ...prev]));

      // Clear the updated symbols set after animation completes
      if (updateTimeoutRef.current) {
        clearTimeout(updateTimeoutRef.current);
