interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const totalSteps = 5;
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const emailRegex = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/, []);
  const nameError = nameTouched && !name.trim() ? 'Name is required.' : '';
  const emailError = emailTouched && !email.trim() ? 'Email is required.' : emailTouched && !emailRegex.test(email) ? 'Please enter a valid email address.' : '';

  const isStep1Valid = name.trim().length > 0 && emailRegex.test(email);
  const isStep2Valid = satisfaction !== '';
  const isCurrentStepValid =
    step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;

  const progressValue = (step / totalSteps) * 100;

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!isStep1Valid) {
        return;
      }
    }
    if (step === 2 && !isStep2Valid) {
      return;
    }
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [step, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments,
    });
  }, [submit, name, email, satisfaction, features, comments]);

  const stepHeadingRef = useRef<HTMLHeadingElement | null>(null);
  useEffect(() => {
    if (stepHeadingRef.current) {
      stepHeadingRef.current.focus();
    }
  }, [step]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                Step {step} of {totalSteps}
              </Text>
              <Badge variant="primary">
                {Math.round(progressValue)}%
              </Badge>
            </Row>
            <Progress value={progressValue} max={100} />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={1}>Survey Form</Heading>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Basic Information</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError || undefined}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError || undefined}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Satisfaction Rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={(props.satisfactionLabels || []).map((label, index) => ({
                    value: String(index + 1),
                    label: `${index + 1} - ${label}`,
                  }))}
                  error={!isStep2Valid ? 'Please choose a rating to continue.' : undefined}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">
                  Select all features you are interested in.
                </Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {(props.featureOptions || []).map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => handleFeatureToggle(feature, checked)}
                    />
                  ))}
                  {(!props.featureOptions || props.featureOptions.length === 0) && (
                    <Alert variant="info" title="No features available">
                      Feature options are currently unavailable.
                    </Alert>
                  )}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Additional Comments</Heading>
                <TextArea
                  label="Comments"
                  value={comments}
                  onChange={setComments}
                  maxLength={500}
                  showCount
                  placeholder="Share any additional thoughts..."
                  helperText="Optional"
                  rows={6}
                />
                <Card padding="var(--ggui-spacing-4)" border>
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between">
                      <Text variant="label">Name</Text>
                      <Text>{name || '—'}</Text>
                    </Row>
                    <Row justify="between">
                      <Text variant="label">Email</Text>
                      <Text>{email || '—'}</Text>
                    </Row>
                    <Row justify="between">
                      <Text variant="label">Satisfaction</Text>
                      <Text>
                        {satisfaction
                          ? `${satisfaction} - ${(props.satisfactionLabels || [])[Number(satisfaction) - 1] || ''}`
                          : '—'}
                      </Text>
                    </Row>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label">Selected Features</Text>
                      {features.length > 0 ? (
                        <Row gap="var(--ggui-spacing-2)" wrap>
                          {features.map((feature) => (
                            <Tag key={feature} variant="primary">
                              {feature}
                            </Tag>
                          ))}
                        </Row>
                      ) : (
                        <Text color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                      )}
