interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
const DEFAULT_COLUMNS = ['todo', 'in-progress', 'done'];
const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function getPriorityBadgeVariant(priority?: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

function normalizeTask(task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, index: number) {
  return {
    id: task.id || `task-${index}-${Date.now()}` ,
    title: task.title || 'Untitled task',
    priority: task.priority || 'low' as 'low' | 'medium' | 'high',
    assignee: task.assignee || '',
    column: task.column || 'todo',
    dueDate: task.dueDate || '',
  };
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string }>>([]);
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    const next = (props.tasks || []).map((task, index) => normalizeTask(task, index));
    setTasksState(next);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = normalizeTask(taskChanged.latest.task, taskChanged.all.length);
    setTasksState((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((t) => t.id !== incoming.id);
      }
      const existingIndex = prev.findIndex((t) => t.id === incoming.id);
      if (existingIndex === -1) {
        return [...prev, incoming];
      }
      const updated = [...prev];
      updated[existingIndex] = { ...updated[existingIndex], ...incoming };
      return updated;
    });
  }, [taskChanged.latest, taskChanged.all.length]);

  const allColumns = useMemo(() => {
    const fromProps = (props.columns || []).map((column, index) => ({
      id: column.id || DEFAULT_COLUMNS[index] || `column-${index}`,
      name: column.name || `Column ${index + 1}`,
    }));
    if (fromProps.length > 0) return fromProps;
    return [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ];
  }, [props.columns]);

  const totalTasks = tasksState.length;
  const completedColumnId = (allColumns.find((c) => (c.name || '').toLowerCase() === 'done')?.id) || 'done';
  const completedTasks = tasksState.filter((task) => task.column === completedColumnId).length;

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasksState((prev) => prev.map((task) => task.id === taskId ? { ...task, column: targetColumn } : task));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const saveTaskTitle = useCallback((taskId: string) => {
    const title = editingTitle.trim();
    if (!title) return;
    const existingTask = tasksState.find((t) => t.id === taskId);
    const updatedTask = {
      title,
      priority: existingTask?.priority || 'low',
      assignee: existingTask?.assignee || '',
      dueDate: existingTask?.dueDate || '',
      column: existingTask?.column || 'todo',
    };
    setTasksState((prev) => prev.map((task) => task.id === taskId ? { ...task, title } : task));
    setEditingTaskId('');
    setEditingTitle('');
    taskUpdate({ action: 'edit', taskId, data: updatedTask as unknown as { column: string } });
  }, [editingTitle, taskUpdate, tasksState]);

  const addTask = useCallback((columnId: string) => {
    const title = newTaskTitle.trim();
    if (!title) return;
    const newTaskId = `task-${Date.now()}`;
    const created = {
      id: newTaskId,
      title,
      priority: newTaskPriority,
      assignee: '',
      column: 'todo',
      dueDate: '',
    };
    setTasksState((prev) => [...prev, created]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId('');
    taskUpdate({
      action: 'create',
      taskId: newTaskId,
      data: {
        column: 'todo',
        title: created.title,
        priority: created.priority,
        assignee: created.assignee,
        dueDate: created.dueDate,
      } as unknown as { column: string },
    });
  }, [newTaskPriority, newTaskTitle, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" wrap>
            <Heading level={3}>Kanban Board</Heading>
            <Row gap="var(--ggui-spacing-3)" wrap>
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedTasks}</Badge>
              <Badge variant={taskChanged.latest ? 'info' : 'default'}>
                Updates: {taskChanged.all.length}
              </Badge>
            </Row>
          </Row>
        </Card>

        {tasksState.length === 0 ? (
          <Alert variant="info" title="No tasks yet">
            Add your first task to get started.
          </Alert>
        ) : null}

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {allColumns.map((column) => {
            const columnTasks = tasksState.filter((task) => task.column === column.id);
            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                        <Stack gap="var(--ggui-spacing-2)">
                          {editingTaskId === task.id ? (
                            <Row gap="var(--ggui-spacing-2)" align="end" wrap>
                              <Input label="Edit title" value={editingTitle} onChange={setEditingTitle} />
                              <Button as={Clickable} onClick={() => saveTaskTitle(task.id)} size="sm">Save</Button>
                              <Button as={Clickable} onClick={() => { setEditingTaskId(''); setEditingTitle(''); }} variant="ghost" size="sm">Cancel</Button>
                            </Row>
                          ) : (
                            <Row justify="between" align="center" wrap>
                              <Text as={Clickable} onDoubleClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title); }} weight="medium">
                                {task.title}
                              </Text>
                              <Button as={Clickable} onClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title); }} variant="ghost" size="sm">Edit</Button>
                            </Row>
                          )}

                          <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                            <Badge variant={getPriorityBadgeVariant(task.priority)}>{task.priority}</Badge>
                            <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                            {task.dueDate ? <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Due: {task.dueDate}</Text> : null}
                          </Row>

                          <Select
                            label="Move to"
                            value={task.column}
                            onChange={(value) => moveTask(task.id, value)}
                            options={allColumns.map((target) => ({ value: target.id, label: target.name }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {addingColumnId === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" border radius="md" shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input label="Task title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter title" />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button as={Clickable} onClick={() => addTask(column.id)} size="sm">Create Task</Button>
                          <Button as={Clickable} onClick={() => { setAddingColumnId(''); setNewTaskTitle(''); setNewTaskPriority('medium'); }} variant="ghost" size="sm">Cancel</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : null}

                  <Button as={Clickable} onClick={() => setAddingColumnId(column.id)} variant="outline">
                    Add Task
                  </Button>
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>

  );
}

