interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed
const getCurrencySymbol = (currencyCode?: string): string => {
  if (!currencyCode) return '';
  const upper = currencyCode.toUpperCase();
  const symbols: Record<string, string> = { USD: '$', EUR: '€', GBP: '£', JPY: '¥', INR: '₹', AUD: 'A$', CAD: 'C$' };
  return symbols[upper] || `${upper} `;
};

const renderStars = (rating?: number, accessibilityLabel?: string) => {
  const normalized = Math.max(0, Math.min(5, Math.round(rating || 0)));
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      <Text is="span" variant="caption" color="var(--ggui-color-onSurfaceVariant)">
        {accessibilityLabel || `Rated ${normalized} out of 5 stars`}
      </Text>
      {Array.from({ length: 5 }).map((_, index) => (
        <Text key={`star-${index}`} is="span" color={index < normalized ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}>
          ★
        </Text>
      ))}
    </Row>
  );
};


const asRecord = (value: unknown): Record<string, unknown> => {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return {};
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);

  const maxStock = Math.max(0, props.product.stock || 0);
  const isOutOfStock = maxStock <= 0;
  const isLowStock = maxStock > 0 && maxStock <= 5;

  useEffect(() => {
    if (isOutOfStock) {
      setQuantity(1);
      return;
    }
    setQuantity((prev) => Math.max(1, Math.min(prev, maxStock)));
  }, [maxStock, isOutOfStock]);

  const formattedPrice = useMemo(() => {
    const symbol = getCurrencySymbol(props.product.currency);
    return `${symbol}${(props.product.price || 0).toFixed(2)}`;
  }, [props.product.currency, props.product.price]);

  const specRows = useMemo(() => {
    return (props.product.specifications || []).map((spec, index) => {
      const row = asRecord(spec);
      const keyValue = row.key ?? row.name ?? row.label ?? `Spec ${index + 1}`;
      const valValue = row.value ?? row.detail ?? row.specification ?? '-';
      return {
        id: `spec-${index}`,
        key: String(keyValue),
        value: String(valValue),
      };
    });
  }, [props.product.specifications]);

  const reviewRows = useMemo(() => {
    return (props.product.reviews || []).map((review, index) => {
      const row = asRecord(review);
      return {
        id: `review-${index}`,
        author: String(row.author ?? row.name ?? 'Anonymous'),
        rating: Number(row.rating ?? 0),
        text: String(row.text ?? row.comment ?? ''),
        date: String(row.date ?? row.createdAt ?? ''),
      };
    });
  }, [props.product.reviews]);

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => Math.min(prev + 1, Math.max(1, maxStock)));
  }, [maxStock]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (isOutOfStock || !props.product.id) return;
    addToCart({ productId: props.product.id, quantity });
  }, [addToCart, isOutOfStock, props.product.id, quantity]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                gap: 'var(--ggui-spacing-4)',
                alignItems: 'start',
              }}
            >
              <Image
                src=""
                alt={props.product.name || 'Product image'}
                width="100%"
                height={280}
                objectFit="cover"
                borderRadius="var(--ggui-shape-radius-lg)"
                fallback={
                  <Box
                    padding="var(--ggui-spacing-8)"
                    background="var(--ggui-color-primary-50)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{ minHeight: '280px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                    aria-label={props.product.name || 'Product image placeholder'}
                  >
                    <Stack justify="center" align="center" gap="var(--ggui-spacing-2)">
                      <Icon name="image" size={32} color="var(--ggui-color-primary-600)" aria-hidden="true" />
                      <Text align="center" color="var(--ggui-color-primary-700)" weight="medium">
                        {props.product.name || 'Unnamed Product'}
                      </Text>
                    </Stack>
                  </Box>
                }
              />

              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={2}>{props.product.name || 'Unnamed Product'}</Heading>
                <Text size="2xl" weight="bold" color="var(--ggui-color-primary-700)">
                  {formattedPrice}
                </Text>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  {renderStars(props.product.rating, `Rated ${Math.max(0, Math.min(5, Math.round(props.product.rating || 0)))} out of 5 stars`)}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    ({props.product.reviewCount || 0} reviews)
                  </Text>
                </Row>
                <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
                  {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
                </Badge>
                {isOutOfStock && <Alert variant="warning">This product is currently out of stock.</Alert>}
              </Stack>
            </Box>
          </Stack>

        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    {props.product.description || 'No description available.'}
                  </Text>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: specRows.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification' },
                      { key: 'value', header: 'Value' },
                    ]}
                    data={specRows}
                    bordered
                  />
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: reviewRows.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-3)">
                    {reviewRows.map((review) => (
                      <Card key={review.id} padding="var(--ggui-spacing-4)" shadow="none" border>
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center">
                            <Text weight="semibold">{review.author}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
                          </Row>
                          {renderStars(review.rating, `Rated ${Math.max(0, Math.min(5, Math.round(review.rating || 0)))} out of 5 stars`)}
                          <Text color="var(--ggui-color-onSurfaceVariant)">{review.text}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Button
                variant="outline"
                as={Clickable}
                onClick={handleDecrement}
                disabled={quantity <= 1 || isOutOfStock}
                aria-label="Decrease quantity"
              >
                -
              </Button>
              <Input
                label="Quantity"
                value={String(quantity)}
                onChange={(value) => {
                  const parsed = Number(value);
                  if (Number.isNaN(parsed)) return;
                  setQuantity(Math.max(1, Math.min(parsed, Math.max(1, maxStock))));
                }}
                type="number"
                disabled={isOutOfStock}
              />
              <Button
                variant="outline"
                as={Clickable}
                onClick={handleIncrement}
                disabled={quantity >= maxStock || isOutOfStock}
                aria-label="Increase quantity"
              >
                +
              </Button>
            </Row>
            <Button variant="primary" as={Clickable} onClick={handleAddToCart} disabled={isOutOfStock || !props.product.id}>
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

