import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed
const formatTimestamp = (value?: string): string => {
  if (!value) {
    return 'Unknown time';
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return 'Unknown time';
  }
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draftMessage, setDraftMessage] = useState<string>('');
  const [typingState, setTypingState] = useState<StreamTyping | null>(null);
  const scrollAreaRef = useRef<HTMLDivElement | null>(null);
  const endRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) {
      return;
    }
    setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) {
      return;
    }
    setTypingState(typing.latest);
  }, [typing.latest]);

  useEffect(() => {
    if (endRef.current) {
      endRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [allMessages, typingState]);

  const canSend = draftMessage.trim().length > 0;

  const groupedMessages = useMemo(() => {
    const source = allMessages ?? [];
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    source.forEach((item) => {
      const last = groups[groups.length - 1];
      if (last && (last.sender ?? 'Unknown') === (item.sender ?? 'Unknown')) {
        last.items.push(item);
      } else {
        groups.push({ sender: item.sender, items: [item] });
      }
    });
    return groups;
  }, [allMessages]);

  const handleSend = useCallback(() => {
    const text = draftMessage.trim();
    if (!text) {
      return;
    }
    const timestamp = new Date().toISOString();
    sendMessage({ text, timestamp });
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text, timestamp }]);
    setDraftMessage('');
  }, [draftMessage, sendMessage, props.currentUser]);

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        handleSend();
      }
    },
    [handleSend],
  );

  const isTypingVisible =
    Boolean(typingState?.active) &&
    Boolean(typingState?.sender) &&
    (typingState?.sender ?? '') !== props.currentUser;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-4)"
        shadow="sm"
        radius="lg"
        border
      >
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3} color="var(--ggui-color-onSurface)">
              {props.title}
            </Heading>
            <Badge variant="primary" size="md">
              {props.participantCount} participants
            </Badge>
          </Row>

          {isTypingVisible ? (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {(typingState?.sender ?? 'Someone') + ' is typing...'}
            </Text>
          ) : null}

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack
              gap="var(--ggui-spacing-3)"
            >
              <Box>
                <div
                  ref={scrollAreaRef}
                  style={{
                    maxHeight: '60vh',
                    overflowY: 'auto',
                    padding: 'var(--ggui-spacing-1)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    {groupedMessages.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
                        No messages yet.
                      </Text>
                    ) : (
                      groupedMessages.map((group, groupIndex) => {
                        const groupSender = group.sender ?? 'Unknown';
                        const isCurrentUser = groupSender === props.currentUser;
                        return (
                          <Stack
                            key={groupSender + '-' + String(groupIndex)}
                            gap="var(--ggui-spacing-1)"
                            align={isCurrentUser ? 'end' : 'start'}
                          >
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                              {groupSender}
                            </Text>
                            {group.items.map((item, itemIndex) => (
                              <Box
                                key={groupSender + '-' + String(groupIndex) + '-' + String(itemIndex)}
                                padding="var(--ggui-spacing-2)"
                                background={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-600)'
                                    : 'var(--ggui-color-surfaceVariant)'
                                }
                                borderRadius="var(--ggui-shape-radius-md)"
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Text
                                    variant="bodySmall"
                                    color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                  >
                                    {item.text ?? ''}
                                  </Text>
                                  <Text
                                    variant="caption"
                                    color={
                                      isCurrentUser
                                        ? 'var(--ggui-color-primary-100)'
                                        : 'var(--ggui-color-onSurfaceVariant)'
                                    }
                                    align={isCurrentUser ? 'right' : 'left'}
                                  >
                                    {formatTimestamp(item.timestamp)}
                                  </Text>
                                </Stack>
                              </Box>
                            ))}
                          </Stack>
                        );
                      })
                    )}
                    <div ref={endRef} />
                  </Stack>
                </div>
              </Box>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box
                  padding="0"
                  background="transparent"
                  borderRadius="var(--ggui-shape-radius-md)"
                  margin="0"
                >
                  <Input
                    label="Message"
                    placeholder="Type a message"
                    value={draftMessage}
                    onChange={setDraftMessage}
                    onKeyDown={handleKeyDown}
                  />
                </Box>
                <Text
                  as={Clickable}
                  onClick={canSend ? handleSend : undefined}
                  is="span"
                  color={canSend ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-onSurfaceVariant)'}
                >
                  <Button variant="primary" disabled={!canSend}>
                    Send
                  </Button>
                </Text>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

