import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
function formatPrice(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--';
  return value.toFixed(2);
}

function formatSigned(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--';
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}`;
}

function formatPercent(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--';
  const sign = value > 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}%`;
}

function getDirection(change?: number): 'up' | 'down' | 'flat' {
  if (typeof change !== 'number' || Number.isNaN(change) || change === 0) return 'flat';
  return change > 0 ? 'up' : 'down';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks || []);
  const [updatedAt, setUpdatedAt] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocksState(props.stocks || []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setUpdatedAt(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) return;
    const symbolKey = priceUpdate.latest.symbol;

    setStocksState((prev) => {
      const next = (prev || []).map((stock) => {
        if (stock.symbol !== symbolKey) return stock;
        return {
          ...stock,
          price: typeof priceUpdate.latest?.price === 'number' ? priceUpdate.latest.price : stock.price,
          change: typeof priceUpdate.latest?.change === 'number' ? priceUpdate.latest.change : stock.change,
          changePercent: typeof priceUpdate.latest?.changePercent === 'number' ? priceUpdate.latest.changePercent : stock.changePercent,
        };
      });
      return next;
    });

    setUpdatedAt(new Date());
    setFlashMap((prev) => ({ ...prev, [symbolKey]: Date.now() }));
  }, [priceUpdate.latest]);

  const marketStatusLabel = useMemo(() => {
    if (!marketStatus.latest?.status) return 'live';
    return marketStatus.latest.status;
  }, [marketStatus.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm" radius="lg">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Last Updated: {updatedAt.toLocaleTimeString()}
                </Text>
                <Badge variant={marketStatusLabel === 'open' ? 'success' : marketStatusLabel === 'closed' ? 'error' : 'warning'} size="sm">
                  {marketStatusLabel}
                </Badge>
              </Row>
            </Stack>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Stream events: {priceUpdate.all.length}
            </Text>
          </Row>
        </Card>

        {!stocksState || stocksState.length === 0 ? (
          <Alert variant="info" title="No stock data">
            No stocks are currently available.
          </Alert>
        ) : (
          <Box>
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
                gap: 'var(--ggui-spacing-4)',
              }}
            >
              {stocksState.map((stock, index) => {
                const symbol = stock.symbol || `stock-${index}`;
                const direction = getDirection(stock.change);
                const toneColor =
                  direction === 'up'
                    ? 'var(--ggui-color-success-700)'
                    : direction === 'down'
                    ? 'var(--ggui-color-error-700)'
                    : 'var(--ggui-color-onSurfaceVariant)';
                const borderColor =
                  direction === 'up'
                    ? 'var(--ggui-color-success-500)'
                    : direction === 'down'
                    ? 'var(--ggui-color-error-500)'
                    : 'var(--ggui-color-outline)';

                return (
                  <Card
                    key={`${symbol}-${flashMap[symbol] || 0}`}
                    padding="var(--ggui-spacing-4)"
                    border
                    radius="lg"
                    shadow="sm"
                  >
                    <Stack
                      gap="var(--ggui-spacing-2)"
                      style={{
                        border: `1px solid ${borderColor}`,
                        borderRadius: 'var(--ggui-shape-radius-md)',
                        padding: 'var(--ggui-spacing-3)',
                        animation: 'ggui-flash 300ms ease-out',
                        ['--ggui-flash-color' as string]:
                          direction === 'up'
                            ? 'var(--ggui-color-success-100)'
                            : direction === 'down'
                            ? 'var(--ggui-color-error-100)'
                            : 'var(--ggui-color-primary-100)',
                      }}
                    >
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown Company'}
                      </Text>
                      <Heading level={3} color="var(--ggui-color-onSurface)">
                        {stock.symbol || '—'}
                      </Heading>
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                        ${formatPrice(stock.price)}
                      </Text>
                      <Row gap="var(--ggui-spacing-2)" align="center">
                        <Text variant="bodySmall" color={toneColor}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Text variant="bodySmall" weight="semibold" color={toneColor}>
                          {direction === 'up' ? '▲' : direction === 'down' ? '▼' : '•'} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Box>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '🙂'));
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');
  const [submitted, setSubmitted] = useState(false);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const step1Valid = useMemo(() => name.trim().length > 0 && emailValid && avatar.trim().length > 0, [name, emailValid, avatar]);
  const step2Valid = useMemo(() => role.trim().length > 0 && (theme === 'light' || theme === 'dark'), [role, theme]);
  const canNext = useMemo(() => (step === 1 ? step1Valid : step === 2 ? step2Valid : true), [step, step1Valid, step2Valid]);
  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const nextStep = useCallback(() => {
    if (!canNext) return;
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canNext]);

  const prevStep = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const submit = useCallback(() => {
    if (!step1Valid || !step2Valid) return;
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar: avatar.trim(),
      role: role.trim(),
      emailNotifications,
      theme,
    };
    complete(payload);
    setSubmitted(true);
  }, [step1Valid, step2Valid, name, email, avatar, role, emailNotifications, theme, complete]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="md">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {step === 1 && 'Set up your profile details.'}
              {step === 2 && 'Choose your preferences.'}
              {step === 3 && 'Review and confirm your setup.'}
            </Text>
          </Stack>
        </Card>

        <Box
          key={step}
          style={{ animation: 'ggui-fadeIn 200ms ease-out' } as React.CSSProperties}
        >
          {step === 1 && (
            <Card padding="var(--ggui-spacing-5)" shadow="sm">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={name.trim().length === 0 ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length === 0 ? 'Email is required.' : !emailValid ? 'Enter a valid email address.' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {(props.avatarOptions.length > 0 ? props.avatarOptions.slice(0, 4) : ['🙂', '😎', '🚀', '🎨']).map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        border
                        shadow="none"
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        } as React.CSSProperties}
                      >
                        <Stack align="center" gap="var(--ggui-spacing-1)">
                          <Text size="2xl">{option}</Text>
                          {avatar === option && <Badge size="sm" variant="success">Selected</Badge>}
                        </Stack>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            </Card>
          )}

          {step === 2 && (
            <Card padding="var(--ggui-spacing-5)" shadow="sm">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={(props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((opt) => ({ value: opt, label: opt }))}
                  error={role.trim().length === 0 ? 'Role is required.' : undefined}
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Theme preference</Text>
                  <Row gap="var(--ggui-spacing-2)">
                    <Button
                      variant={theme === 'light' ? 'primary' : 'outline'}
                      onClick={() => setTheme('light')}
                    >
                      Light
                    </Button>
                    <Button
                      variant={theme === 'dark' ? 'primary' : 'outline'}
                      onClick={() => setTheme('dark')}
                    >
                      Dark
                    </Button>
                  </Row>
                </Stack>
              </Stack>
            </Card>
          )}

          {step === 3 && (
            <Card padding="var(--ggui-spacing-5)" shadow="sm">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your information">
                  You can go back to make changes before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" shadow="none" border>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            </Card>
          )}
        </Box>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={prevStep} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button variant="primary" onClick={nextStep} disabled={!canNext}>
                Next
              </Button>
            )}
            {step === 3 && (
              <>
                <Button variant="outline" onClick={prevStep}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={submit} disabled={!step1Valid || !step2Valid}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>

        {submitted && (
          <Alert variant="success" title="Setup complete">
            Your onboarding details were submitted successfully.
          </Alert>
        )}
      </Stack>
    </Container>

  );
}
